const MODULES = [
  { key: 'terminal', name: 'Terminal Convexity V1', paramsKey: 'terminalParams' },
  { key: 'cofre', name: 'Cofre Sete V1', paramsKey: 'cofreParams' },
  { key: 'impulse', name: 'Impulse Elasticity V1', paramsKey: 'impulseParams' },
  { key: 'edge', name: 'Edge Sniper V1', paramsKey: 'edgeParams' },
  { key: 'gamma', name: 'Gamma Ladder V1', paramsKey: 'gammaParams' },
];

const DEFAULT_PARAMS = {
  walletSize: 100,
  selectionMode: 'stack',
  includeModules: ['terminal', 'cofre', 'impulse', 'edge', 'gamma'],
  priority: ['terminal', 'cofre', 'impulse', 'edge', 'gamma'],
  maxStackedModulesPerEvent: 0,
  edgeParams: {},
  gammaParams: {},
  cofreParams: {},
  impulseParams: {},
  terminalParams: {},
};

function toFiniteNumber(value) {
  if (value == null || value === '') return null;
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : null;
}

function normalizeStringList(value, fallback) {
  if (Array.isArray(value)) {
    const clean = value.map((item) => String(item).trim()).filter(Boolean);
    return clean.length ? clean : fallback;
  }
  if (typeof value === 'string') {
    const clean = value.split(',').map((item) => item.trim()).filter(Boolean);
    return clean.length ? clean : fallback;
  }
  return fallback;
}

function normalizeSelectionMode(value) {
  const mode = String(value || DEFAULT_PARAMS.selectionMode).toLowerCase();
  return ['stack', 'single'].includes(mode) ? mode : DEFAULT_PARAMS.selectionMode;
}

function normalizeObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function mergeFusionFiveParams(raw = {}) {
  const params = {
    ...DEFAULT_PARAMS,
    edgeParams: normalizeObject(raw.edgeParams ?? raw.edge ?? DEFAULT_PARAMS.edgeParams),
    gammaParams: normalizeObject(raw.gammaParams ?? raw.gamma ?? DEFAULT_PARAMS.gammaParams),
    cofreParams: normalizeObject(raw.cofreParams ?? raw.cofre ?? DEFAULT_PARAMS.cofreParams),
    impulseParams: normalizeObject(raw.impulseParams ?? raw.impulse ?? DEFAULT_PARAMS.impulseParams),
    terminalParams: normalizeObject(raw.terminalParams ?? raw.terminal ?? DEFAULT_PARAMS.terminalParams),
  };

  const walletSize = toFiniteNumber(raw.walletSize);
  if (walletSize != null) params.walletSize = Math.max(1, walletSize);

  for (const module of MODULES) {
    if (params[module.paramsKey].walletSize == null) {
      params[module.paramsKey] = { ...params[module.paramsKey], walletSize: params.walletSize };
    }
  }

  params.selectionMode = normalizeSelectionMode(raw.selectionMode ?? raw.mode);
  params.includeModules = normalizeStringList(raw.includeModules, DEFAULT_PARAMS.includeModules)
    .filter((key) => MODULES.some((module) => module.key === key));
  if (!params.includeModules.length) params.includeModules = [...DEFAULT_PARAMS.includeModules];

  params.priority = normalizeStringList(raw.priority, DEFAULT_PARAMS.priority)
    .filter((key) => MODULES.some((module) => module.key === key));
  if (!params.priority.length) params.priority = [...DEFAULT_PARAMS.priority];

  const maxStacked = toFiniteNumber(raw.maxStackedModulesPerEvent ?? raw.stackLimit);
  if (maxStacked != null) params.maxStackedModulesPerEvent = Math.max(0, Math.floor(maxStacked));

  return params;
}

function eventKey(event) {
  return `${event.eventStart}|${event.eventId}`;
}

function isActiveEvent(event) {
  return event && event.reason !== 'no_entry' && Number(event.cost || 0) > 0;
}

function priorityIndex(params, moduleKey) {
  const index = params.priority.indexOf(moduleKey);
  return index === -1 ? params.priority.length + 1 : index;
}

function moduleEventScore(item) {
  const event = item.event;
  const diagnostics = event.diagnostics || {};
  const edge = Number(diagnostics.modelEdge ?? diagnostics.edge ?? diagnostics.probability ?? 0);
  const timeRemaining = Number(event.entryTimeRemaining ?? 0);
  return edge + (timeRemaining * 0.000001);
}

function shouldKeepModuleEvent(params, event) {
  if (!isActiveEvent(event)) return false;
  return true;
}

function decorateEvent(module, event) {
  return {
    ...event,
    fusionModule: module.key,
    fusionModuleName: module.name,
    fusionEventKey: eventKey(event),
  };
}

function selectEvents(params, moduleResults) {
  const grouped = new Map();

  for (const moduleResult of moduleResults) {
    if (!params.includeModules.includes(moduleResult.key)) continue;
    for (const event of moduleResult.result.events || []) {
      if (!shouldKeepModuleEvent(params, event)) continue;
      const key = eventKey(event);
      const item = { module: moduleResult, event };
      if (!grouped.has(key)) grouped.set(key, []);
      grouped.get(key).push(item);
    }
  }

  const selected = [];
  for (const items of grouped.values()) {
    items.sort((left, right) => {
      const priorityDelta = priorityIndex(params, left.module.key) - priorityIndex(params, right.module.key);
      if (priorityDelta !== 0) return priorityDelta;
      return moduleEventScore(right) - moduleEventScore(left);
    });

    if (params.selectionMode === 'single') {
      selected.push(decorateEvent(items[0].module, items[0].event));
      continue;
    }

    const limit = params.maxStackedModulesPerEvent > 0 ? params.maxStackedModulesPerEvent : items.length;
    for (const item of items.slice(0, limit)) selected.push(decorateEvent(item.module, item.event));
  }

  return selected.sort((left, right) => new Date(left.closedAt || left.eventEnd) - new Date(right.closedAt || right.eventEnd));
}

function buildEventUniverse(moduleResults) {
  const eventsByKey = new Map();
  for (const moduleResult of moduleResults) {
    for (const event of moduleResult.result.events || []) {
      const key = eventKey(event);
      if (!eventsByKey.has(key)) eventsByKey.set(key, event);
    }
  }
  return eventsByKey;
}

function createNoEntryEvent(baseEvent, key) {
  return {
    eventId: baseEvent.eventId,
    eventStart: baseEvent.eventStart,
    eventEnd: baseEvent.eventEnd,
    positionType: null,
    entryTime: null,
    entryDistanceToPtb: null,
    entryTimeRemaining: null,
    quantity: 0,
    cost: 0,
    avgEntryPrice: 0,
    fills: [],
    profitOrders: [],
    exits: [],
    expirationResult: null,
    winnerSide: baseEvent.winnerSide ?? null,
    expiryPnl: 0,
    finalPnl: 0,
    reason: 'no_entry',
    closedAt: baseEvent.closedAt || baseEvent.eventEnd,
    diagnostics: null,
    fusionModule: null,
    fusionModuleName: null,
    fusionEventKey: key,
  };
}

function buildDisplayEvents(selectedEvents, moduleResults) {
  const universe = buildEventUniverse(moduleResults);
  const selectedKeys = new Set(selectedEvents.map((event) => event.fusionEventKey));
  const noEntryEvents = [];
  for (const [key, event] of universe.entries()) {
    if (!selectedKeys.has(key)) noEntryEvents.push(createNoEntryEvent(event, key));
  }
  return [...selectedEvents, ...noEntryEvents]
    .sort((left, right) => new Date(left.closedAt || left.eventEnd) - new Date(right.closedAt || right.eventEnd));
}

function std(values) {
  if (values.length < 2) return 0;
  const avg = values.reduce((sum, value) => sum + value, 0) / values.length;
  return Math.sqrt(values.reduce((sum, value) => sum + (value - avg) ** 2, 0) / values.length);
}

function computeSummary(events, selectedEvents, params, moduleResults) {
  const pnls = selectedEvents.map((event) => Number(event.finalPnl || 0));
  const wins = pnls.filter((value) => value > 0);
  const losses = pnls.filter((value) => value < 0);
  const totalPnl = pnls.reduce((sum, value) => sum + value, 0);
  const grossProfit = wins.reduce((sum, value) => sum + value, 0);
  const grossLoss = losses.reduce((sum, value) => sum + Math.abs(value), 0);
  const totalEntries = selectedEvents.length;
  const totalWins = wins.length;
  const totalLosses = losses.length;
  const avgPnl = totalEntries > 0 ? totalPnl / totalEntries : 0;
  const avgWin = wins.length ? grossProfit / wins.length : 0;
  const avgLoss = losses.length ? grossLoss / losses.length : 0;
  const pnlStd = std(pnls);
  const downsideStd = std(losses);
  const uniqueMarketEvents = new Set(events.map((event) => event.fusionEventKey)).size;
  const activeMarketEvents = new Set(selectedEvents.map((event) => event.fusionEventKey)).size;

  const equity = [];
  let cumulative = 0;
  let peak = 0;
  let maxDrawdown = 0;
  for (const event of events) {
    cumulative += Number(event.finalPnl || 0);
    if (cumulative > peak) peak = cumulative;
    maxDrawdown = Math.max(maxDrawdown, peak - cumulative);
    equity.push({ ts: event.closedAt || event.eventEnd, pnl: cumulative });
  }

  const byModule = {};
  for (const event of selectedEvents) {
    const key = event.fusionModule;
    if (!byModule[key]) byModule[key] = { module: key, entries: 0, pnl: 0, wins: 0, losses: 0 };
    byModule[key].entries += 1;
    byModule[key].pnl += Number(event.finalPnl || 0);
    if (Number(event.finalPnl || 0) > 0) byModule[key].wins += 1;
    else if (Number(event.finalPnl || 0) < 0) byModule[key].losses += 1;
  }

  return {
    totalEvents: uniqueMarketEvents,
    totalEntries,
    activeEvents: activeMarketEvents,
    stackedEntries: Math.max(0, totalEntries - activeMarketEvents),
    totalNoEntry: Math.max(0, uniqueMarketEvents - activeMarketEvents),
    totalWins,
    totalLosses,
    winRate: totalEntries > 0 ? parseFloat(((totalWins / totalEntries) * 100).toFixed(1)) : 0,
    totalPnl,
    avgPnl,
    maxWin: pnls.length ? Math.max(...pnls) : 0,
    maxLoss: pnls.length ? Math.min(...pnls) : 0,
    maxDrawdown,
    finalWallet: params.walletSize + totalPnl,
    grossProfit,
    grossLoss,
    profitFactor: grossLoss > 0 ? grossProfit / grossLoss : (grossProfit > 0 ? Number.POSITIVE_INFINITY : 0),
    payoff: avgLoss > 0 ? avgWin / avgLoss : (avgWin > 0 ? Number.POSITIVE_INFINITY : 0),
    expectancy: avgPnl,
    sharpe: pnlStd > 0 ? avgPnl / pnlStd : 0,
    sortino: downsideStd > 0 ? avgPnl / downsideStd : 0,
    modules: Object.values(byModule),
  };
}

function buildFusionFiveResultFromResults(rawParams, moduleResults) {
  const params = mergeFusionFiveParams(rawParams);
  const selectedEvents = selectEvents(params, moduleResults);
  const displayEvents = buildDisplayEvents(selectedEvents, moduleResults);
  const summary = computeSummary(displayEvents, selectedEvents, params, moduleResults);
  const equity = [];
  let cumulative = 0;
  for (const event of displayEvents) {
    cumulative += Number(event.finalPnl || 0);
    equity.push({ ts: event.closedAt || event.eventEnd, pnl: cumulative });
  }

  return {
    params,
    strategy: 'FUSION_FIVE_V1',
    summary,
    equity,
    events: displayEvents,
    moduleResults: moduleResults.map((item) => ({
      key: item.key,
      name: item.name,
      summary: item.result.summary,
      strategy: item.result.strategy,
    })),
    log: [],
    ticksProcessed: moduleResults.reduce((maxValue, item) => Math.max(maxValue, item.result.ticksProcessed || 0), 0),
    periodStart: moduleResults.find((item) => item.result.periodStart)?.result.periodStart || null,
    periodEnd: [...moduleResults].reverse().find((item) => item.result.periodEnd)?.result.periodEnd || null,
  };
}

function createBacktestRunner(rawParams = {}, loadChildRunner) {
  const params = mergeFusionFiveParams(rawParams);
  const __MODULE_SLUGS__ = {
  "terminal": "terminal-convexity-runner",
  "cofre": "cofre-sete-runner",
  "impulse": "impulse-elasticity-runner",
  "edge": "edge-sniper-runner",
  "gamma": "gamma-ladder-runner"
};
  const moduleRunners = MODULES.map((module) => ({
    ...module,
    runner: loadChildRunner(__MODULE_SLUGS__[module.key], 1, params[module.paramsKey] || {}),
  }));

  const processTick = (tick) => {
    for (const module of moduleRunners) module.runner.processTick(tick);
  };

  const finish = () => {
    const moduleResults = moduleRunners.map((module) => ({
      key: module.key,
      name: module.name,
      result: module.runner.finish(),
    }));
    return buildFusionFiveResultFromResults(params, moduleResults);
  };

  return { processTick, finish };
}

function runFusionFiveBacktest(rawParams, ticks) {
  const runner = createFusionFiveBacktestRunner(rawParams);
  for (const tick of ticks) runner.processTick(tick);
  return runner.finish();
}

async function runFusionFiveBacktestInBatches(rawParams, tickBatches) {
  const runner = createFusionFiveBacktestRunner(rawParams);
  for await (const batch of tickBatches) {
    for (const tick of batch) runner.processTick(tick);
  }
  return runner.finish();
}
